import{_ as e,o as l,c as a,a2 as o}from"./chunks/framework.CMAFtOGK.js";const p=JSON.parse('{"title":"02 毛泽东思想","description":"政治理论 · 02 毛泽东思想","frontmatter":{"title":"02 毛泽东思想","description":"政治理论 · 02 毛泽东思想","category":"politics-note"},"headers":[],"relativePath":"posts/politics/notes/02-毛泽东思想.md","filePath":"posts/politics/notes/02-毛泽东思想.md","lastUpdated":1784753089000}'),s={name:"posts/politics/notes/02-毛泽东思想.md"};function r(n,t,i,d,g,h){return l(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="_02-毛泽东思想及其历史地位" tabindex="-1">02 毛泽东思想及其历史地位 <a class="header-anchor" href="#_02-毛泽东思想及其历史地位" aria-label="Permalink to &quot;02 毛泽东思想及其历史地位&quot;">​</a></h1><blockquote><p>🎯 <strong>一句话</strong>：毛泽东思想是马克思主义中国化的<strong>第一次历史性飞跃</strong>。</p></blockquote><hr><h2 id="一、形成与发展-时间轴" tabindex="-1">一、形成与发展（时间轴） <a class="header-anchor" href="#一、形成与发展-时间轴" aria-label="Permalink to &quot;一、形成与发展（时间轴）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">阶段</th><th style="text-align:left;">标志</th><th style="text-align:left;">要点</th></tr></thead><tbody><tr><td style="text-align:left;">萌芽</td><td style="text-align:left;">大革命时期</td><td style="text-align:left;">农民运动、阶级分析</td></tr><tr><td style="text-align:left;">初步形成</td><td style="text-align:left;">土地革命时期</td><td style="text-align:left;">农村包围城市、武装夺取政权</td></tr><tr><td style="text-align:left;">成熟</td><td style="text-align:left;">延安整风至七大</td><td style="text-align:left;">系统总结，写入党章</td></tr><tr><td style="text-align:left;">继续发展</td><td style="text-align:left;">解放战争、新中国成立后</td><td style="text-align:left;">人民民主专政、社会主义改造等</td></tr></tbody></table><p><strong>党的七大（1945）</strong>：确立毛泽东思想为党的指导思想。</p><hr><h2 id="二、活的灵魂-必背-3-条" tabindex="-1">二、活的灵魂（必背 3 条） <a class="header-anchor" href="#二、活的灵魂-必背-3-条" aria-label="Permalink to &quot;二、活的灵魂（必背 3 条）&quot;">​</a></h2><ol><li><strong>实事求是</strong>（精髓）</li><li><strong>群众路线</strong>（根本工作路线）</li><li><strong>独立自主</strong>（根本立足点）</li></ol><hr><h2 id="三、历史地位" tabindex="-1">三、历史地位 <a class="header-anchor" href="#三、历史地位" aria-label="Permalink to &quot;三、历史地位&quot;">​</a></h2><ul><li>马克思主义中国化的<strong>第一次历史性飞跃</strong></li><li>中国革命和建设的科学指南</li><li>中国共产党和中国人民宝贵的精神财富</li><li>必须把毛泽东思想与毛泽东晚年错误<strong>区别开来</strong>（十一届六中全会《历史决议》精神）</li></ul><hr><h2 id="四、闭卷挑战" tabindex="-1">四、闭卷挑战 <a class="header-anchor" href="#四、闭卷挑战" aria-label="Permalink to &quot;四、闭卷挑战&quot;">​</a></h2><p><strong>1.</strong> 毛泽东思想活的灵魂是什么？</p><blockquote><p><strong>点击查看答案与解析</strong> 实事求是、群众路线、独立自主。</p></blockquote><p><strong>2.</strong> 毛泽东思想何时被确立为党的指导思想？</p><blockquote><p><strong>点击查看答案与解析</strong> 1945 年党的七大。</p></blockquote><p>返回：01-马克思主义中国化时代化 · <a href="/zhuan-sheng-ben-notes/posts/politics/">政治</a></p>',19)])])}const _=e(s,[["render",r]]);export{p as __pageData,_ as default};
